const express = require('express')
const cors = require('cors')
const app = express()
app.use(cors())
app.use(express.json())

// In-memory products (replace with DB)
let products = [
  { id: 1, name: '5G Smartphone', category: 'mobile', price: 14999, oldPrice: 18999, badge: '20% OFF', image: 'https://via.placeholder.com/600x400?text=Phone', rating: 4 },
  { id: 2, name: 'Wireless Headphones', category: 'electronics', price: 1999, oldPrice: null, badge: 'BEST', image: 'https://via.placeholder.com/600x400?text=Headphone', rating: 5 },
]

// Get all products or filter by category / search
app.get('/api/products', (req, res) => {
  const q = (req.query.q || '').toLowerCase()
  const cat = req.query.category
  let resList = products
  if (cat) resList = resList.filter(p => p.category === cat)
  if (q) resList = resList.filter(p => p.name.toLowerCase().includes(q))
  res.json(resList)
})

app.get('/api/products/:id', (req, res) => {
  const p = products.find(x => x.id === Number(req.params.id))
  if (!p) return res.status(404).json({ error: 'Not found' })
  res.json(p)
})

// Simple admin add (no auth in starter)
app.post('/api/products', (req, res) => {
  const { name, category, price, oldPrice, badge, image } = req.body
  const id = products.length ? Math.max(...products.map(p=>p.id))+1 : 1
  const p = { id, name, category, price, oldPrice: oldPrice || null, badge: badge || '', image, rating: 0 }
  products.push(p)
  res.status(201).json(p)
})

const port = process.env.PORT || 4000
app.listen(port, ()=>console.log('API running on http://localhost:' + port))

