import { NextResponse } from 'next/server'
import prisma from '../../../../lib/prisma'

export async function GET(request: Request, { params }: { params: { slug: string } }) {
  const { slug } = params
  const product = await prisma.product.findUnique({ where: { slug } })
  if (!product || !product.approved) {
    return new NextResponse('Not found', { status: 404 })
  }

  // Try to capture some metadata
  const ua = request.headers.get('user-agent') || undefined
  const ref = request.headers.get('referer') || undefined
  // X-Forwarded-For may contain client IP
  const ip = request.headers.get('x-forwarded-for') || undefined

  try {
    await prisma.click.create({
      data: {
        productId: product.id,
        userAgent: ua,
        referrer: ref,
        ip
      }
    })
  } catch (err) {
    // Logging failure must not block redirect
    console.error('Click log error', err)
  }

  return NextResponse.redirect(product.affiliateUrl, 302)
}

